import React, { useState } from "react";
import "./Sidebar.css"; // Make sure to create a CSS file for styling

const Sidebar = () => {
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  const toggleSidebar = () => {
    setIsSidebarOpen(!isSidebarOpen);
  };

  return (
    <div
      className={`sidebar ${isSidebarOpen ? "open" : "closed"}`}
      id="sidebar"
    >
      <div className="sidebar-header">
        <div className="sidebar-logo">
          <img src="logo.png" alt="Bring Your Buddy Logo" />
        </div>
        <div className="sidebar-toggle-desktop">
          <button className="toggle-btn" onClick={toggleSidebar}>
            <i
              className={`fas ${isSidebarOpen ? "fa-chevron-left" : "fa-chevron-right"}`}
            ></i>
          </button>
        </div>
      </div>

      <ul className="sidebar-menu">
        <li className="sidebar-menu-item active">
          <a href="#">
            <div className="menu-icon">
              <i className="fas fa-home"></i>
            </div>
            <span className="menu-text">Dashboard</span>
          </a>
        </li>
        <li className="sidebar-menu-item">
          <a href="#">
            <div className="menu-icon">
              <i className="fas fa-user-friends"></i>
            </div>
            <span className="menu-text">Buddies</span>
          </a>
        </li>
        <li className="sidebar-menu-item">
          <a href="#">
            <div className="menu-icon">
              <i className="fas fa-calendar-alt"></i>
            </div>
            <span className="menu-text">Events</span>
          </a>
        </li>
        <li className="sidebar-menu-item">
          <a href="#">
            <div className="menu-icon">
              <i className="fas fa-comment-alt"></i>
            </div>
            <span className="menu-text">Messages</span>
          </a>
        </li>
        <li className="sidebar-menu-item">
          <a href="#">
            <div className="menu-icon">
              <i className="fas fa-map-marker-alt"></i>
            </div>
            <span className="menu-text">Places</span>
          </a>
        </li>
        <li className="sidebar-menu-item">
          <a href="#">
            <div className="menu-icon">
              <i className="fas fa-cog"></i>
            </div>
            <span className="menu-text">Settings</span>
          </a>
        </li>
      </ul>

      <div className="sidebar-footer">
        <a href="/login" className="logout-btn">
          <div className="menu-icon">
            <i className="fas fa-sign-out-alt"></i>
          </div>
          <span className="menu-text">Logout</span>
        </a>
      </div>
    </div>
  );
};

export default Sidebar;
